mapper.select:
SELECT id, course_id AS courseId, video_id AS videoId, user_id AS userId, rating, comment_content AS commentContent, like_count AS likeCount, reply_count AS replyCount, is_anonymous AS isAnonymous, status, created_time AS createdTime, updated_time AS updatedTime FROM course_comment
AND course_id = #{q.courseId}
AND video_id = #{q.videoId}
AND user_id = #{q.userId}
AND rating = #{q.rating}
AND status = #{q.status}
AND created_time BETWEEN #{q.beginTime} AND #{q.endTime}
ORDER BY created_time DESC

